let raw =   $input.first().json.content.parts[0].text;

raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

let data;
try {
  data = JSON.parse(raw);
} catch (err) {
  throw new Error("Invalid JSON after cleanup: " + err + "\nRaw:\n" + raw);
}

// Return cleaned object
return {
  json: data
};

